pub fn thread_tasks_subject(thread_id: &str) -> String {
    format!("dd.remote.thread.{}.tasks", thread_id)
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ThreadTasksSubjectParts {
    pub thread_id: String,
}

pub fn parse_thread_tasks_subject(subject: &str) -> Option<ThreadTasksSubjectParts> {
    let pattern_tokens: &[&str] = &["dd", "remote", "thread", "{thread_id}", "tasks"];
    let subject_tokens: Vec<&str> = subject.split('.').collect();
    let mut thread_id: Option<String> = None;
    let mut si: usize = 0;
    for tok in pattern_tokens.iter() {
        if tok.starts_with('{') && tok.ends_with('}') {
            if si >= subject_tokens.len() { return None; }
            let name = &tok[1..tok.len()-1];
            match name {
                "thread_id" => { thread_id = Some(subject_tokens[si].to_string()); }
                _ => return None,
            }
            si += 1;
            continue;
        }
        if si >= subject_tokens.len() || subject_tokens[si] != *tok { return None; }
        si += 1;
    }
    if si != subject_tokens.len() { return None; }
    Some(ThreadTasksSubjectParts {
        thread_id: thread_id?,
    })
}

